import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyForecast {
  day: string;
  temp: number;
}

interface WeatherData {
  location: string;
  current: {
    temp: number;
    condition: string;
    humidity: number;
    windSpeed: number;
  };
  weeklyForecast: WeeklyForecast[];
  tempTrend: number[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const weatherData = response.data as WeatherData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {weatherData.location}
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ my: 0.5 }}>
              {weatherData.current.temp}°
            </Typography>
            <Typography variant="body1" color="text.secondary">
              {weatherData.current.condition}
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: weatherData.tempTrend,
                color: metaData.accentColor,
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: weatherData.weeklyForecast.map((_, index) => index), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={3}>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Humidity
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {weatherData.current.humidity}%
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Wind
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {weatherData.current.windSpeed} mph
              </Typography>
            </Box>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
